    Pages,
    Categories,
    ConfigSecrets,
    ConfigValues,
    ConfigAuditLogs,
    Conversations,
    GuestSessions,
    MemoryItems,
    Tenants,
    Courses,
    Chapters,
    Lessons,
    Exercises,
    ExtractionLogs,
    Prompts,
    TeacherProfiles,
